        self.yaml_file.parent.mkdir(parents=True, exist_ok=True)
        with self.yaml_file.open('w') as handle:
            pprint_dict(self.format_to_printable_dict(), handle)
            # TRIED EXPERIMENTING HERE BUT IT WASN'T SO PRETTY \"
